import requests
from flask import Flask, request, jsonify
import json

# Create a Flask app
app = Flask(__name__)

# OAuth 2.0 client ID and secret
client_id = 'your_client_id'
client_secret = 'your_client_secret'

# OAuth 2.0 authorization URL
auth_url = 'https://example.com/oauth2/authorize'

# OAuth 2.0 token endpoint URL
token_url = 'https://example.com/oauth2/token'

# OAuth 2.0 scopes
scopes = ['read', 'write']

# OAuth 2.0 authorization URL handler
@app.route('/authorize', methods=['GET', 'POST'])
def authorize():
    if request.method == 'GET':
        return redirect(auth_url + '?response_type=code&client_id=' + client_id + '&redirect_uri=' + request.host_url + '&scope=' + ' '.join(scopes))
    elif request.method == 'POST':
        return 'Invalid request method'

# OAuth 2.0 token endpoint handler
@app.route('/token', methods=['POST'])
def token():
    if request.method == 'POST':
        # Extract client credentials and authorization code
        client_id = request.form['client_id']
        client_secret = request.form['client_secret']
        code = request.form['code']
        redirect_uri = request.form['redirect_uri']

        # Verify client credentials
        if client_id != client_id or client_secret != client_secret:
            return jsonify({'error': 'invalid_client'}), 401

        # Exchange authorization code for access token
        headers = {'Content-Type': 'application/x-www-form-urlencoded'}
        data = {'grant_type': 'authorization_code', 'code': code, 'redirect_uri': redirect_uri}
        response = requests.post(token_url, headers=headers, data=data, auth=(client_id, client_secret))
        if response.status_code == 200:
            return jsonify(response.json()), 200
        else:
            return jsonify({'error': 'invalid_grant'}), 401

# Run the Flask app
if __name__ == '__main__':
    app.run(debug=True)

import logging
from flask import Flask, jsonify, request
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    name = db.Column(db.String(100), nullable=False)
    email = db.Column(db.String(100), unique=True, nullable=False)

    def __repr__(self):
        return f'User({self.name}, {self.email})'

@app.route('/users', methods=['GET'])
def get_users():
    users = User.query.all()
    return jsonify([{'id': user.id, 'name': user.name, 'email': user.email} for user in users])

@app.route('/users', methods=['POST'])
def create_user():
    data = request.get_json()
    if 'name' not in data or 'email' not in data:
        return jsonify({'error': 'Missing required fields'}), 400
    user = User(name=data['name'], email=data['email'])
    db.session.add(user)
    db.session.commit()
    return jsonify({'id': user.id, 'name': user.name, 'email': user.email}), 201

@app.route('/users/<int:user_id>', methods=['GET'])
def get_user(user_id):
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    return jsonify({'id': user.id, 'name': user.name, 'email': user.email})

@app.route('/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    data = request.get_json()
    if 'name' in data:
        user.name = data['name']
    if 'email' in data:
        user.email = data['email']
    db.session.commit()
    return jsonify({'id': user.id, 'name': user.name, 'email': user.email})

@app.route('/users/<int:user_id>', methods=['DELETE'])
def delete_user(user_id):
    user = User.query.get(user_id)
    if user is None:
        return jsonify({'error': 'User not found'}), 404
    db.session.delete(user)
    db.session.commit()
    return jsonify({'message': 'User deleted'})

if __name__ == '__main__':
    app.run(debug=True)

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel

app = FastAPI()

# Define a resource
class Resource(BaseModel):
    id: int
    name: str

# In-memory storage for demonstration purposes
resources = [
    Resource(id=1, name='Resource 1'),
    Resource(id=2, name='Resource 2')
]

# GET /resources
@app.get('/resources')
def get_resources():
    return resources

# GET /resources/{resource_id}
@app.get('/resources/{resource_id}')
def get_resource(resource_id: int):
    for resource in resources:
        if resource.id == resource_id:
            return resource
    raise HTTPException(status_code=404, detail='Resource not found')

# POST /resources
@app.post('/resources')
def create_resource(resource: Resource):
    resources.append(resource)
    return resource

# PUT /resources/{resource_id}
@app.put('/resources/{resource_id}')
def update_resource(resource_id: int, new_resource: Resource):
    for i, resource in enumerate(resources):
        if resource.id == resource_id:
            resources[i] = new_resource
            return new_resource
    raise HTTPException(status_code=404, detail='Resource not found')

# DELETE /resources/{resource_id}
@app.delete('/resources/{resource_id}')
def delete_resource(resource_id: int):
    for i, resource in enumerate(resources):
        if resource.id == resource_id:
            del resources[i]
            return {'message': 'Resource deleted'}
    raise HTTPException(status_code=404, detail='Resource not found')

