// Import required modules
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

// Create an Express app
const app = express();

// Middleware to parse JSON requests
app.use(express.json());

// In-memory user data store (replace with a database in production)
const users = [
  { id: 1, username: 'john', password: bcrypt.hashSync('hello', 10) }
];

// Function to authenticate a user
function authenticate(req, res) {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username);

  if (!user) {
    // Return 401 Unauthorized if user is not found
    res.status(401).json({ error: 'Invalid username or password' });
  } else if (!bcrypt.compareSync(password, user.password)) {
    // Return 401 Unauthorized if password is incorrect
    res.status(401).json({ error: 'Invalid username or password' });
  } else {
    // Generate a JSON Web Token (JWT) for the authenticated user
    const token = jwt.sign({ userId: user.id }, 'secret-key', { expiresIn: '1h' });
    res.json({ token });
  }
}

// API endpoint to authenticate a user
app.post('/login', authenticate);

// Error handling middleware
app.use((err, req, res, next) => {
  // Log the error
  console.error(err);

  // Return a 500 Internal Server Error response
  res.status(500).json({ error: 'Internal Server Error' });
});

// Start the server
const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
